import bluesky.plan_stubs as bps
from bluesky.preprocessors import inject_md_decorator


def some_plan(dae):
    run_number = yield from bps.rd(dae.current_or_next_run_number_str)

    @inject_md_decorator({"run_number": run_number})
    def _inner():
        yield from subplan()

    yield from _inner()
